import React from "react";

function Scoreboard({ runs, wickets, balls, maxBalls, maxWickets }) {
  const overs = Math.floor(balls / 6);
  const ballsInOver = balls % 6;
  const ballsLeft = maxBalls - balls;

  return (
    <div className="scoreboard">
      <div className="score-item">
        <span className="score-label">RUNS</span>
        <span className="score-value">{runs}</span>
      </div>
      <div className="score-divider" />
      <div className="score-item">
        <span className="score-label">WICKETS</span>
        <span className="score-value">
          {wickets}
          <span className="score-sub">/{maxWickets}</span>
        </span>
      </div>
      <div className="score-divider" />
      <div className="score-item">
        <span className="score-label">OVERS</span>
        <span className="score-value">
          {overs}.{ballsInOver}
          <span className="score-sub">/2.0</span>
        </span>
      </div>
      <div className="score-divider" />
      <div className="score-item">
        <span className="score-label">BALLS LEFT</span>
        <span className="score-value balls-left">{ballsLeft}</span>
      </div>
    </div>
  );
}

export default Scoreboard;
